import axios from 'axios';
import React, { useEffect, useState } from 'react'
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { useGetAllProductsQuery } from './MyorderApi';

const MyOrder = () => {
  const [orderData, setRenderData] = useState();
  var userid= sessionStorage.getItem("UserInfoID")

  useEffect(()=>{
    getAllData()
    
  })



  useEffect(() => {
    const fetchData = async () => {
      await fetch(`http://localhost:1313/myorder/${userid}`)
        .then(async (res) => {
          const data = await res.json();
          console.log(data)
          setRenderData(data?.data);
        })
        .catch((err) => {
          console.log("err", err);
        });
    };
    fetchData();
  }, []);

  const getAllData=()=>{
    axios.get(`http://localhost:1313/myorder/${userid}`).then((res_new)=>{
      //  const allData = res.data.orderData.allData;
      
       console.log(res_new?.data)
      //  setorderData(allData)
    }).catch(error =>{
      console.log("Error",error)
    })
  }


  return (
    <div>
      my order {orderData}
    </div>
  )
}

export default MyOrder
